example.code:
// Good - exhaustive check
function assertNever(x: never): never {
  throw new Error(`Unexpected value: ${x}`);
}

function handleShape(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
    default:
      return assertNever(shape); // compile error if case is missing
  }
}

// Good
export class NotFoundError extends Error {
  readonly code = "NOT_FOUND" as const;
  constructor(
    readonly entityType: string,
    readonly entityId: string,
  ) {
    super(`${entityType} not found: ${entityId}`);
    this.name = "NotFoundError";
  }
}

// Good
try {
  await fetchData();
} catch (error) {
  if (error instanceof NotFoundError) {
    return handleNotFound(error.entityId);
  }
  if (error instanceof Error) {
    logger.error(error.message, { stack: error.stack });
  }
  throw error;
}

// Bad - assumes error is Error
try {
  await fetchData();
} catch (error) {
  console.log(error.message); // error is unknown
}

// Good
type Result<T, E = Error> =
  | { ok: true; value: T }
  | { ok: false; error: E };

function parseEmail(input: string): Result<Email, ValidationError> {
  if (!EMAIL_RE.test(input)) {
    return { ok: false, error: new ValidationError("Invalid email") };
  }
  return { ok: true, value: input as Email };
}

// Caller must handle both cases
const result = parseEmail(input);
if (!result.ok) {
  showError(result.error);
  return;
}
sendEmail(result.value);

// Good - type guard
function isUser(value: unknown): value is User {
  return (
    typeof value === "object" &&
    value !== null &&
    "id" in value &&
    "name" in value
  );
}

// Good - assertion function
function assertDefined<T>(value: T | undefined, msg: string): asserts value is T {
  if (value === undefined) throw new Error(msg);
}

// Good - validate at boundary
import { z } from "zod";

const UserSchema = z.object({
  id: z.string().uuid(),
  name: z.string().min(1),
  email: z.string().email(),
});
type User = z.infer<typeof UserSchema>;

// API handler
const user = UserSchema.parse(req.body);
